export default class Vector {
    x: number;
    y: number;
    z: number;
    constructor(x: number, y: number, z: number);
    minus(vec: Vector): Vector;
    add(vec: Vector): Vector;
    crossProduct(vec: Vector): Vector;
    length(): number;
    euclideanDistanceTo(vec: Vector): number;
    multiplyScalar(scalar: number): Vector;
    normalized(): Vector;
}
